import Foundation

class EqualizerManager {
    static let shared = EqualizerManager()
    private let userDefaults = UserDefaults.standard
    private let presetKey = "lastSelectedEqualizerPreset"

    func save(presetName: String) {
        userDefaults.set(presetName, forKey: presetKey)
    }

    func load() -> String? {
        return userDefaults.string(forKey: presetKey)
    }
}
```

### ✅ Android (Kotlin)
```kotlin
import android.content.Context

class EqualizerManager(context: Context) {
    private val prefs = context.getSharedPreferences("equalizer_prefs", Context.MODE_PRIVATE)
    private val presetKey = "last_selected_preset"

    fun save(presetName: String) {
        prefs.edit().putString(presetKey, presetName).apply()
    }

    fun load(): String? {
        return prefs.getString(presetKey, null)
    }
}
